"use client";

import { Kbd, KbdGroup } from "@/shared/ui/kbd";
import { useHotkeyStore } from "../model/hotkey-store";

function parseAccelerator(accelerator: string): string[] {
	return accelerator.split("+").map((key) => {
		switch (key) {
			case "Control":
				return "Ctrl";
			case "Meta":
				return "Win";
			default:
				return key;
		}
	});
}

export function HotkeyDisplay() {
	const isPressed = useHotkeyStore((s) => s.isPressed);
	const accelerator = useHotkeyStore((s) => s.accelerator);
	const keys = parseAccelerator(accelerator);

	return (
		<div
			className={`flex items-center gap-1.5 rounded px-1.5 py-0.5 transition-all duration-150 ease-in-out ${isPressed ? "border border-border-accent bg-accent-dim" : "border border-transparent"}`}
		>
			<KbdGroup>
				{keys.map((key) => (
					<Kbd className="h-4 min-w-4 text-[10px]" key={key}>
						{key}
					</Kbd>
				))}
			</KbdGroup>
			{isPressed && (
				<span className="inline-block size-1 animate-recording-pulse rounded-full bg-accent" />
			)}
		</div>
	);
}
