"use client";

import {
	CloudIcon,
	Plug01Icon,
	WifiDisconnected01Icon,
	WifiFullSignalIcon,
} from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { useConnectionStore } from "../model/connection-store";

const STATUS_CONFIG = {
	disconnected: {
		color: "var(--color-error)",
		label: "OFFLINE",
		icon: WifiDisconnected01Icon,
	},
	connecting: {
		color: "var(--color-warning)",
		label: "CONNECTING",
		icon: CloudIcon,
	},
	connected: {
		color: "var(--color-success)",
		label: "ONLINE",
		icon: WifiFullSignalIcon,
	},
	error: {
		color: "var(--color-error)",
		label: "ERROR",
		icon: Plug01Icon,
	},
} as const;

export function ConnectionIndicator() {
	const status = useConnectionStore((s) => s.connectionStatus);
	const config = STATUS_CONFIG[status];

	return (
		<div className="flex items-center gap-1.5">
			<HugeiconsIcon color={config.color} icon={config.icon} size={13} />
			<span className="font-medium text-[11px]" style={{ color: config.color }}>
				{config.label}
			</span>
		</div>
	);
}
